+// transactionalReloadManager owns the last known-good configuration and the
+// persisted outcome of explicit configuration reload attempts.
+type transactionalReloadManager struct {
+	mu       sync.RWMutex
+	status   api_v1.ReloadStatus
+	lastGood *config.Config
+	filename string
+	logger   *slog.Logger
+}
+
+func newTransactionalReloadManager(filename string, logger *slog.Logger) *transactionalReloadManager {
+	m := &transactionalReloadManager{
+		status: api_v1.ReloadStatus{
+			ErrorCategory:     "none",
+			AppliedReloaders:  []string{},
+			ReloaderTimingsMS: map[string]int64{},
+		},
+		filename: filename,
+		logger:   logger,
+	}
+	data, err := os.ReadFile(filename)
+	if err != nil {
+		if !errors.Is(err, os.ErrNotExist) {
+			logger.Warn("Unable to read persisted reload status", "err", err)
+		}
+		return m
+	}
+	if err := json.Unmarshal(data, &m.status); err != nil {
+		logger.Warn("Unable to parse persisted reload status", "err", err)
+		m.status = api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+		return m
+	}
+	if m.status.AppliedReloaders == nil {
+		m.status.AppliedReloaders = []string{}
+	}
+	if m.status.ReloaderTimingsMS == nil {
+		m.status.ReloaderTimingsMS = map[string]int64{}
+	}
+	return m
+}
+
+func (m *transactionalReloadManager) Status() api_v1.ReloadStatus {
+	m.mu.RLock()
+	defer m.mu.RUnlock()
+	s := m.status
+	s.AppliedReloaders = slices.Clone(m.status.AppliedReloaders)
+	s.ReloaderTimingsMS = maps.Clone(m.status.ReloaderTimingsMS)
+	return s
+}
+
+func (m *transactionalReloadManager) setLastGood(conf *config.Config) {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	m.lastGood = conf
+}
+
+func (m *transactionalReloadManager) recordLoadError(err error) {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	m.status = m.newStatus(false, "load_error", err.Error())
+	m.persistLocked()
+}
+
+func (m *transactionalReloadManager) apply(conf *config.Config, rls []reloader) error {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+
+	status := m.newStatus(false, "apply_error", "")
+	for _, rl := range rls {
+		started := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(started))
+		if err == nil {
+			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+			continue
+		}
+
+		status.ErrorMessage = err.Error()
+		status.FailedReloader = rl.name
+		if len(status.AppliedReloaders) > 0 && m.lastGood != nil {
+			status.RollbackAttempted = true
+			status.RollbackSuccessful = true
+			for _, rollbackReloader := range rls {
+				if rollbackErr := rollbackReloader.reloader(m.lastGood); rollbackErr != nil {
+					status.RollbackSuccessful = false
+					status.ErrorCategory = "rollback_error"
+					status.ErrorMessage = fmt.Sprintf("apply failed in %s: %v; rollback failed in %s: %v", rl.name, err, rollbackReloader.name, rollbackErr)
+					break
+				}
+			}
+		}
+		m.status = status
+		m.persistLocked()
+		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+	}
+
+	status.LastReloadSuccessful = true
+	status.ErrorCategory = "none"
+	m.status = status
+	m.lastGood = conf
+	m.persistLocked()
+	return nil
+}
+
+func (m *transactionalReloadManager) newStatus(successful bool, category, message string) api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{
+		LastReloadID:       time.Now().UTC().Format(time.RFC3339),
+		LastReloadSuccessful: successful,
+		ErrorCategory:      category,
+		ErrorMessage:       message,
+		AppliedReloaders:   []string{},
+		ReloaderTimingsMS:  map[string]int64{},
+	}
+}
+
+func (m *transactionalReloadManager) persistLocked() {
+	data, err := json.Marshal(m.status)
+	if err != nil {
+		m.logger.Warn("Unable to marshal reload status", "err", err)
+		return
+	}
+	if err := os.MkdirAll(filepath.Dir(m.filename), 0o755); err != nil {
+		m.logger.Warn("Unable to create reload status directory", "err", err)
+		return
+	}
+	tmp := m.filename + ".tmp"
+	if err := os.WriteFile(tmp, data, 0o644); err != nil {
+		m.logger.Warn("Unable to persist reload status", "err", err)
+		return
+	}
+	if err := os.Rename(tmp, m.filename); err != nil {
+		m.logger.Warn("Unable to finalize reload status", "err", err)
+	}
+}
